# Generated by anthropic (claude-sonnet-4-5)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

properties([
    parameters([
        string(name: 'ARTIFACT_URL', defaultValue: '', description: 'URL to download the artifact from (supports S3, Artifactory, HTTP/HTTPS)'),
        string(name: 'ARTIFACT_NAME', defaultValue: 'application.jar', description: 'Name to save the artifact as'),
        choice(name: 'ENVIRONMENT', choices: ['staging', 'production'], description: 'Target environment'),
        string(name: 'PRODUCTION_SERVERS', defaultValue: 'prod-server1,prod-server2,prod-server3', description: 'Comma-separated list of production servers'),
        string(name: 'STAGING_SERVERS', defaultValue: 'staging-server1', description: 'Comma-separated list of staging servers'),
        string(name: 'DEPLOY_PATH', defaultValue: '/opt/application', description: 'Deployment path on target servers'),
        string(name: 'SERVICE_NAME', defaultValue: 'application', description: 'Service name to restart after deployment'),
        credentials(name: 'SSH_CREDENTIALS', description: 'SSH credentials for deployment servers', required: true, credentialType: 'com.cloudbees.plugins.credentials.impl.UsernamePasswordMultiBinding'),
        credentials(name: 'ARTIFACT_CREDENTIALS', description: 'Credentials for artifact repository (optional)', required: false, credentialType: 'com.cloudbees.plugins.credentials.impl.UsernamePasswordMultiBinding'),
        string(name: 'S3_BUCKET', defaultValue: '', description: 'S3 bucket name (if using S3)'),
        string(name: 'S3_KEY', defaultValue: '', description: 'S3 object key (if using S3)'),
        string(name: 'AWS_REGION', defaultValue: 'us-east-1', description: 'AWS region (if using S3)'),
        booleanParam(name: 'BACKUP_EXISTING', defaultValue: true, description: 'Backup existing artifact before deployment'),
        booleanParam(name: 'VERIFY_CHECKSUM', defaultValue: true, description: 'Verify artifact checksum if available'),
        string(name: 'CHECKSUM_URL', defaultValue: '', description: 'URL to checksum file (optional)'),
        string(name: 'PRE_DEPLOY_SCRIPT', defaultValue: '', description: 'Script to run before deployment (optional)'),
        string(name: 'POST_DEPLOY_SCRIPT', defaultValue: '', description: 'Script to run after deployment (optional)'),
        booleanParam(name: 'ROLLING_DEPLOYMENT', defaultValue: true, description: 'Deploy to servers one at a time'),
        string(name: 'HEALTH_CHECK_URL', defaultValue: '', description: 'Health check URL to verify deployment (optional)')
    ])
])

pipeline {
    agent any
    
    environment {
        WORKSPACE_ARTIFACTS = "${WORKSPACE}/artifacts"
        DEPLOYMENT_TIMESTAMP = sh(script: "date +%Y%m%d_%H%M%S", returnStdout: true).trim()
    }
    
    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    if (!params.ARTIFACT_URL && (!params.S3_BUCKET || !params.S3_KEY)) {
                        error("Either ARTIFACT_URL or S3_BUCKET and S3_KEY must be provided")
                    }
                    
                    if (!params.SSH_CREDENTIALS) {
                        error("SSH_CREDENTIALS must be provided")
                    }
                    
                    echo "Deployment Configuration:"
                    echo "Environment: ${params.ENVIRONMENT}"
                    echo "Artifact: ${params.ARTIFACT_NAME}"
                    echo "Deploy Path: ${params.DEPLOY_PATH}"
                    echo "Service: ${params.SERVICE_NAME}"
                    echo "Rolling Deployment: ${params.ROLLING_DEPLOYMENT}"
                }
            }
        }
        
        stage('Prepare Workspace') {
            steps {
                script {
                    sh "mkdir -p ${WORKSPACE_ARTIFACTS}"
                    sh "rm -f ${WORKSPACE_ARTIFACTS}/*"
                }
            }
        }
        
        stage('Download Artifact') {
            steps {
                script {
                    def artifactPath = "${WORKSPACE_ARTIFACTS}/${params.ARTIFACT_NAME}"
                    
                    if (params.S3_BUCKET && params.S3_KEY) {
                        echo "Downloading artifact from S3: s3://${params.S3_BUCKET}/${params.S3_KEY}"
                        downloadFromS3(params.S3_BUCKET, params.S3_KEY, artifactPath, params.AWS_REGION)
                    } else {
                        echo "Downloading artifact from URL: ${params.ARTIFACT_URL}"
                        downloadFromUrl(params.ARTIFACT_URL, artifactPath)
                    }
                    
                    sh "ls -lh ${artifactPath}"
                    
                    if (params.VERIFY_CHECKSUM && params.CHECKSUM_URL) {
                        verifyChecksum(artifactPath, params.CHECKSUM_URL)
                    }
                }
            }
        }
        
        stage('Verify Artifact') {
            steps {
                script {
                    def artifactPath = "${WORKSPACE_ARTIFACTS}/${params.ARTIFACT_NAME}"
                    
                    if (!fileExists(artifactPath)) {
                        error("Artifact file not found: ${artifactPath}")
                    }
                    
                    def fileSize = sh(script: "stat -f%z '${artifactPath}' 2>/dev/null || stat -c%s '${artifactPath}'", returnStdout: true).trim()
                    echo "Artifact size: ${fileSize} bytes"
                    
                    if (fileSize.toInteger() == 0) {
                        error("Downloaded artifact is empty")
                    }
                    
                    def md5sum = sh(script: "md5sum '${artifactPath}' | awk '{print \$1}'", returnStdout: true).trim()
                    echo "Artifact MD5: ${md5sum}"
                    env.ARTIFACT_MD5 = md5sum
                }
            }
        }
        
        stage('Deploy to Servers') {
            steps {
                script {
                    def servers = params.ENVIRONMENT == 'production' ? 
                        params.PRODUCTION_SERVERS.split(',') : 
                        params.STAGING_SERVERS.split(',')
                    
                    def artifactPath = "${WORKSPACE_ARTIFACTS}/${params.ARTIFACT_NAME}"
                    
                    if (params.ROLLING_DEPLOYMENT) {
                        echo "Starting rolling deployment to ${servers.size()} server(s)"
                        for (server in servers) {
                            deployToServer(server.trim(), artifactPath)
                        }
                    } else {
                        echo "Starting parallel deployment to ${servers.size()} server(s)"
                        def deploySteps = [:]
                        for (server in servers) {
                            def currentServer = server.trim()
                            deploySteps[currentServer] = {
                                deployToServer(currentServer, artifactPath)
                            }
                        }
                        parallel deploySteps
                    }
                }
            }
        }
        
        stage('Verify Deployment') {
            when {
                expression { params.HEALTH_CHECK_URL }
            }
            steps {
                script {
                    def servers = params.ENVIRONMENT == 'production' ? 
                        params.PRODUCTION_SERVERS.split(',') : 
                        params.STAGING_SERVERS.split(',')
                    
                    echo "Verifying deployment health..."
                    sleep(time: 10, unit: 'SECONDS')
                    
                    for (server in servers) {
                        def healthUrl = params.HEALTH_CHECK_URL.replace('SERVER_PLACEHOLDER', server.trim())
                        def maxRetries = 5
                        def retryCount = 0
                        def healthy = false
                        
                        while (retryCount < maxRetries && !healthy) {
                            try {
                                def response = sh(script: "curl -s -o /dev/null -w '%{http_code}' ${healthUrl}", returnStdout: true).trim()
                                if (response == '200') {
                                    echo "Server ${server.trim()} is healthy (HTTP ${response})"
                                    healthy = true
                                } else {
                                    echo "Server ${server.trim()} returned HTTP ${response}, retrying..."
                                    retryCount++
                                    sleep(time: 5, unit: 'SECONDS')
                                }
                            } catch (Exception e) {
                                echo "Health check failed for ${server.trim()}: ${e.message}"
                                retryCount++
                                sleep(time: 5, unit: 'SECONDS')
                            }
                        }
                        
                        if (!healthy) {
                            error("Health check failed for server ${server.trim()} after ${maxRetries} attempts")
                        }
                    }
                }
            }
        }
    }
    
    post {
        success {
            script {
                echo "Deployment completed successfully!"
                echo "Artifact: ${params.ARTIFACT_NAME}"
                echo "MD5: ${env.ARTIFACT_MD5}"
                echo "Environment: ${params.ENVIRONMENT}"
                echo "Timestamp: ${DEPLOYMENT_TIMESTAMP}"
            }
        }
        failure {
            script {
                echo "Deployment failed! Check logs for details."
            }
        }
        always {
            script {
                sh "rm -rf ${WORKSPACE_ARTIFACTS}"
            }
        }
    }
}

def downloadFromUrl(String url, String destination) {
    if (params.ARTIFACT_CREDENTIALS) {
        withCredentials([usernamePassword(credentialsId: params.ARTIFACT_CREDENTIALS, 
                                          usernameVariable: 'ARTIFACT_USER', 
                                          passwordVariable: 'ARTIFACT_PASS')]) {
            sh """
                curl -f -L -u \${ARTIFACT_USER}:\${ARTIFACT_PASS} -o '${destination}' '${url}'
            """
        }
    } else {
        sh """
            curl -f -L -o '${destination}' '${url}'
        """
    }
}

def downloadFromS3(String bucket, String key, String destination, String region) {
    sh """
        aws s3 cp s3://${bucket}/${key} '${destination}' --region ${region}
    """
}

def verifyChecksum(String artifactPath, String checksumUrl) {
    echo "Verifying artifact checksum..."
    def checksumFile = "${artifactPath}.checksum"
    
    sh """
        curl -f -L -o '${checksumFile}' '${checksumUrl}'
    """
    
    def expectedChecksum = readFile(checksumFile).trim().split()[0]
    def actualChecksum = sh(script: "md5sum '${artifactPath}' | awk '{print \$1}'", returnStdout: true).trim()
    
    if (expectedChecksum != actualChecksum) {
        error("Checksum verification failed! Expected: ${expectedChecksum}, Actual: ${actualChecksum}")
    }
    
    echo "Checksum verified successfully: ${actualChecksum}"
}

def deployToServer(String server, String artifactPath) {
    echo "Deploying to server: ${server}"
    
    withCredentials([usernamePassword(credentialsId: params.SSH_CREDENTIALS, 
                                      usernameVariable: 'SSH_USER', 
                                      passwordVariable: 'SSH_PASS')]) {
        
        if (params.PRE_DEPLOY_SCRIPT) {
            echo "Running pre-deployment script on ${server}"
            sh """
                sshpass -p '\${SSH_PASS}' ssh -o StrictHostKeyChecking=no \${SSH_USER}@${server} '${params.PRE_DEPLOY_SCRIPT}'
            """
        }
        
        if (params.BACKUP_EXISTING) {
            echo "Backing up existing artifact on ${server}"
            sh """
                sshpass -p '\${SSH_PASS}' ssh -o StrictHostKeyChecking=no \${SSH_USER}@${server} \
                "if [ -f ${params.DEPLOY_PATH}/${params.ARTIFACT_NAME} ]; then \
                    cp ${params.DEPLOY_PATH}/${params.ARTIFACT_NAME} ${params.DEPLOY_PATH}/${params.ARTIFACT_NAME}.backup.${DEPLOYMENT_TIMESTAMP}; \
                fi"
            """
        }
        
        echo "Stopping service ${params.SERVICE_NAME} on ${server}"
        sh """
            sshpass -p '\${SSH_PASS}' ssh -o StrictHostKeyChecking=no \${SSH_USER}@${server} \
            "sudo systemctl stop ${params.SERVICE_NAME} || true"
        """
        
        echo "Copying artifact to ${server}:${params.DEPLOY_PATH}"
        sh """
            sshpass -p '\${SSH_PASS}' scp -o StrictHostKeyChecking=no '${artifactPath}' \
            \${SSH_USER}@${server}:${params.DEPLOY_PATH}/${params.ARTIFACT_NAME}
        """
        
        echo "Setting permissions on ${server}"
        sh """
            sshpass -p '\${SSH_PASS}' ssh -o StrictHostKeyChecking=no \${SSH_USER}@${server} \
            "chmod 755 ${params.DEPLOY_PATH}/${params.ARTIFACT_NAME}"
        """
        
        echo "Starting service ${params.SERVICE_NAME} on ${server}"
        sh """
            sshpass -p '\${SSH_PASS}' ssh -o StrictHostKeyChecking=no \${SSH_USER}@${server} \
            "sudo systemctl start ${params.SERVICE_NAME}"
        """
        
        sleep(time: 5, unit: 'SECONDS')
        
        echo "Verifying service status on ${server}"
        def serviceStatus = sh(script: """
            sshpass -p '\${SSH_PASS}' ssh -o StrictHostKeyChecking=no \${SSH_USER}@${server} \
            "sudo systemctl is-active ${params.SERVICE_NAME}"
        """, returnStdout: true).trim()
        
        if (serviceStatus != 'active') {
            error("Service ${params.SERVICE_NAME} is not active on ${server}. Status: ${serviceStatus}")
        }
        
        echo "Service ${params.SERVICE_NAME} is running on ${server}"
        
        if (params.POST_DEPLOY_SCRIPT) {
            echo "Running post-deployment script on ${server}"
            sh """
                sshpass -p '\${SSH_PASS}' ssh -o StrictHostKeyChecking=no \${SSH_USER}@${server} '${params.POST_DEPLOY_SCRIPT}'
            """
        }
    }
    
    echo "Deployment to ${server} completed successfully"
}